/**
 * ci-sign-check.cjs
 *
 * Pre-flight check for Windows code signing environment variables.
 * Run this before `dist:win` in CI to get a clear error if signing
 * credentials are missing, instead of a silent unsigned build.
 *
 * Usage:
 *   node electron/ci-sign-check.cjs [--require-signing]
 *
 * Options:
 *   --require-signing  Exit with code 1 if signing vars are absent
 *                      (use in release pipelines, omit for dev/beta)
 */

"use strict";

const requireSigning = process.argv.includes("--require-signing");

const WIN_CSC_LINK = process.env.WIN_CSC_LINK || "";
const WIN_CSC_KEY_PASSWORD = process.env.WIN_CSC_KEY_PASSWORD || "";

const hasLink = WIN_CSC_LINK.trim().length > 0;
const hasPassword = WIN_CSC_KEY_PASSWORD.trim().length > 0;
const signingReady = hasLink && hasPassword;

if (signingReady) {
  console.log("[ci-sign-check] Code signing credentials present — installer will be signed.");
  process.exit(0);
}

if (!hasLink) {
  console.warn("[ci-sign-check] WARNING: WIN_CSC_LINK is not set.");
}
if (!hasPassword) {
  console.warn("[ci-sign-check] WARNING: WIN_CSC_KEY_PASSWORD is not set.");
}

if (requireSigning) {
  console.error(
    "[ci-sign-check] FATAL: --require-signing is set but signing credentials are missing.\n" +
    "Set WIN_CSC_LINK (base64-encoded .p12 path) and WIN_CSC_KEY_PASSWORD before running dist:win."
  );
  process.exit(1);
}

console.warn(
  "[ci-sign-check] Proceeding WITHOUT code signing — installer will trigger Windows SmartScreen.\n" +
  "Acceptable for beta/internal builds. Set WIN_CSC_LINK + WIN_CSC_KEY_PASSWORD for signed releases."
);
process.exit(0);
